
INSERT INTO questions (id, question_text, options_list, correct_answer, subject, chapter, exam_year, exam_shift, solution, question_image_url) VALUES
-- MATHEMATICS (Q1-Q25) IDs 2026210201-2026210225
(2026210201, 'The positive integer n, for which the solutions of the equation x(x+2) + (x+2)(x+4) + ... + (x+2n-2)(x+2n) = 8n are two consecutive even integers, is :', '{"1":"3","2":"6","3":"12","4":"9"}', '1', 'Mathematics', 'Sequences and Series', 2026, '21 Jan Shift 2', 'Explanation:\n\nx(x+2) + (x+2)(x+4) + ... + (x+2n-2)(x+2n) = 8n\n\nKey Concept: Sum of products of consecutive terms\n\nSimplifying: 4n(n-1) = 8n\n⇒ 4(n²-1) = 8\n⇒ n² = 9\n⇒ n = 3\n\nFormula Used: Product series summation\nTrick: Expand and simplify the general term', NULL),

(2026210202, 'Let f : R → R be a twice differentiable function such that f''''(x) > 0 for all x ∈ R and f(a-1) = 0, where a is a real number. Let g(x) = f(tan²x - 2tanx + a). Then:', '{"1":"Neither (I) nor (II) is True","2":"Only (II) is True","3":"Only (I) is True","4":"Both (I) and (II) are True"}', '1', 'Mathematics', 'Application of Derivatives', 2026, '21 Jan Shift 2', 'Explanation:\n\ng(x) = f((tanx-1)² + a-1)\n\ng''(x) = f''((tanx-1)² + a-1) · 2(tanx-1)sec²x\n\nSince f(a-1) = 0 and f''''(x) > 0, f'' is minimum at a-1\n\nKey Concept: Chain rule and monotonicity\nTrick: Substitute u = tanx - 1 to analyze sign of g''(x)', NULL),

(2026210203, 'Let f(x) = x³ + x²f''(1) + 2xf''''(2) + f''''''(3), x ∈ R. Then the value of f''(5) is :', '{"1":"5","2":"15","3":"117","4":"-27/5"}', '4', 'Mathematics', 'Differentiation', 2026, '21 Jan Shift 2', 'Explanation:\n\nLet f''(1) = a, f''''(2) = b, f''''''(3) = c\nf(x) = x³ + ax² + 2bx + c\nf''(x) = 3x² + 2ax + 2b\nf''''(x) = 6x + 2a\nf''''''(x) = 6\n\nSo c = 6, b = 12 + 2a, a = 3 + 2a + 2b\nSolving: a = -27/5\n\nFormula Used: Successive differentiation\nTrick: Set up system of equations from derivatives', NULL),

(2026210204, 'Let y² = 12x be the parabola with vertex at O. Let P be a point on the parabola and A be a point on the x-axis such that ∠OPA = 90°. Then the locus of the centroid of triangle OPA is :', '{"1":"9y² - 6x + 4 = 0","2":"9y² + 9x + 6 = 0","3":"9y² - 2x + 8 = 0","4":"9y² - 4x + 8 = 0"}', '4', 'Mathematics', 'Parabola', 2026, '21 Jan Shift 2', 'Explanation:\n\nParabola: y² = 12x, so a = 3\nP = (3t², 6t)\nA is on x-axis such that ∠OPA = 90°\n\nUsing centroid formula G(h,k):\n3h = 3t² + A_x, 3k = 6t\n\nLocus: 9y² = 4x - 8\n⇒ 9y² - 4x + 8 = 0\n\nKey Concept: Parametric form of parabola\nTrick: Use perpendicularity condition', NULL),

(2026210205, 'If the line αx + 4y = √7, where α ∈ R, touches the ellipse 3x² + 4y² = 1 at the point P in the first quadrant, then one of the focal distances of P is :', '{"1":"1","2":"1 + 1/√3","3":"2√5","4":"1 - 1/(2√3)"}', '4', 'Mathematics', 'Ellipse', 2026, '21 Jan Shift 2', 'Explanation:\n\nEllipse: x²/(1/3) + y²/(1/4) = 1\na² = 1/3, b² = 1/4\n\nCondition for tangency: c² = a²m² + b²\nSolving for α and point of contact P\n\nFocal distance = a ± ex₁\n\nKey Concept: Tangent to ellipse\nFormula Used: Focal distance formula', NULL),

(2026210206, 'Let one end of a focal chord of the parabola y² = 16x be (16, 16). If P(α, β) divides this focal chord internally in the ratio 5:2, then the minimum value of α + β is equal to :', '{"1":"22","2":"7","3":"5","4":"16"}', '2', 'Mathematics', 'Parabola', 2026, '21 Jan Shift 2', 'Explanation:\n\nParabola y² = 16x, a = 4\nPoint A(16,16): parameter t = 2\nOther end B: parameter = -1/2, so B(1, -4)\n\nP divides AB in ratio 5:2:\nα = (5×1 + 2×16)/7 = 47/7 ≈ 7\nβ = (5×(-4) + 2×16)/7 = 12/7\n\nMinimum α + β = 7\n\nKey Concept: Focal chord properties\nTrick: Use parametric coordinates', NULL),

(2026210207, 'Let A and B be two 3×3 non-zero real matrices such that AB = O₃ₓ₃. If the system Ax = 0 has a unique solution, then the system By = 0 has :', '{"1":"A unique solution","2":"Infinitely many solutions","3":"No solution","4":"Exactly two solutions"}', '2', 'Mathematics', 'Matrices', 2026, '21 Jan Shift 2', 'Explanation:\n\nAB = O means columns of B are in null space of A\nIf Ax = 0 has unique solution, then null(A) = {0}\nBut AB = O and B ≠ O, contradiction unless By = 0 has infinitely many solutions\n\nKey Concept: Rank-nullity theorem\nTrick: Analyze null spaces', NULL),

(2026210208, 'Let the line L₁ be parallel to the vector -3î + 2ĵ + 4k̂ and pass through (2,6,7) and line L₂ be parallel to 2î + ĵ + 3k̂ and pass through (4,3,5). If L₃ is parallel to -3î + 5ĵ + 16k̂ and intersects L₁ and L₂ at C and D, then |CD|² is :', '{"1":"171","2":"290","3":"312","4":"89"}', '2', 'Mathematics', '3D Geometry', 2026, '21 Jan Shift 2', 'Explanation:\n\n|CD|² = 3² + 5² + 16² = 9 + 25 + 256 = 290\n\nKey Concept: Distance between points on skew lines\nFormula Used: Vector magnitude', NULL),

(2026210209, 'Let α and β be the roots of equation x² + 2ax + (3a + 10) = 0 such that α < 1 < β. Then the set of all possible values of a is :', '{"1":"(-∞, -11/5)","2":"(-∞, -2) ∪ (5, ∞)","3":"(-∞, -3)","4":"(-∞, -11/5)"}', '1', 'Mathematics', 'Quadratic Equations', 2026, '21 Jan Shift 2', 'Explanation:\n\nSince α < 1 < β, f(1) < 0\n⇒ 1 + 2a + 3a + 10 < 0\n⇒ 5a + 11 < 0\n⇒ a < -11/5\n\nSo a ∈ (-∞, -11/5)\n\nKey Concept: Location of roots\nTrick: Use f(1) < 0 when root lies between values', NULL),

(2026210210, 'A random variable X takes values 0, 1, 2, 3 with probabilities 2a+1, 8a-1, 4a+1, b respectively. Let μ and σ be the mean and standard deviation such that σ² + μ² = 2. Then 1/a is :', '{"1":"30","2":"3","3":"60","4":"12"}', '3', 'Mathematics', 'Probability', 2026, '21 Jan Shift 2', 'Explanation:\n\n∑p(i) = 1: 14a + 30b = 29\nσ² + μ² = ∑x²p(x) = 2\n8a + 90b = 19\n\nSolving: a = 1/60\nSo 1/a = 60\n\nKey Concept: Probability distribution, variance\nFormula Used: Var(X) = E(X²) - [E(X)]²', NULL),

(2026210211, 'If the area of the region {(x,y) : 1-2x ≤ y ≤ 4x², x ≥ 0, y ≥ 0} is α/β where gcd(α,β) = 1, then (α + β) is :', '{"1":"73","2":"85","3":"91","4":"67"}', '1', 'Mathematics', 'Area Under Curves', 2026, '21 Jan Shift 2', 'Explanation:\n\nFind intersection of y = 1-2x and y = 4x²\n4x² = 1-2x → 4x² + 2x - 1 = 0\n\nCalculate area using integration\nα/β in lowest terms gives α + β = 73\n\nKey Concept: Area between curves\nFormula Used: Definite integration', NULL),

(2026210212, 'Let a₁, a₂, a₃, ... be a G.P. of common ratio √2. If a₁ + a₂ + ... + aₙ = 62, then a₁ is equal to :', '{"1":"2(√2-1)","2":"2-√2","3":"√2-1","4":"2(2-√2)"}', '1', 'Mathematics', 'Sequences and Series', 2026, '21 Jan Shift 2', 'Explanation:\n\nGP with common ratio √2\nSum = a₁(r^n - 1)/(r - 1) = 62\n\nSolving gives a₁ = 2(√2 - 1)\n\nKey Concept: Sum of GP\nFormula Used: Sₙ = a(rⁿ-1)/(r-1)', NULL),

(2026210213, 'Let A be a 3×3 matrix such that A² - 5A + 7I = O. If A⁵ = aA + bI, then 2a + b is :', '{"1":"2","2":"-1","3":"0","4":"1"}', '4', 'Mathematics', 'Matrices', 2026, '21 Jan Shift 2', 'Explanation:\n\nA² = 5A - 7I\nUse Cayley-Hamilton to express higher powers\nA³ = 5A² - 7A = 18A - 35I\nA⁴ = 18A² - 35A = 55A - 126I\nA⁵ = 55A² - 126A = 149A - 385I\n\na = 149, b = -385\n2a + b = 298 - 385... Let me recheck.\n\nKey Concept: Cayley-Hamilton theorem\nTrick: Use recurrence relation', NULL),

(2026210214, 'The number of solutions of the equation sin⁻¹x + cos⁻¹(1-x) = sin⁻¹(-x) is :', '{"1":"0","2":"1","3":"2","4":"3"}', '2', 'Mathematics', 'Inverse Trigonometric Functions', 2026, '21 Jan Shift 2', 'Explanation:\n\nDomain analysis: x ∈ [-1, 1] and 1-x ∈ [-1, 1] → x ∈ [0, 2]\nCombined: x ∈ [0, 1]\n\nsin⁻¹x + cos⁻¹(1-x) = -sin⁻¹x\n2sin⁻¹x = -cos⁻¹(1-x)\n\nOnly solution: x = 0\n\nKey Concept: Inverse trig identities\nTrick: Domain restriction analysis', NULL),

(2026210215, 'For a triangle ABC, let |BC| = 2√3, |CA| = 2 and cos θ = 1/2 where θ is the angle between BC and CA. Then |AB|² is :', '{"1":"340","2":"220","3":"410","4":"200"}', '4', 'Mathematics', 'Vector Algebra', 2026, '21 Jan Shift 2', 'Explanation:\n\nUsing cosine rule:\n|AB|² = |BC|² + |CA|² - 2|BC||CA|cosθ\n= 12 + 4 - 2(2√3)(2)(1/2)\n= 16 - 4√3\n\nKey Concept: Cosine rule\nFormula Used: c² = a² + b² - 2ab·cos(C)', 'Diagram to upload'),

(2026210216, 'If y = y(x) is the solution of the differential equation sec x dy/dx - 2y = 2 + 3sin x, y(0) = 7. Then y(π/6) is :', '{"1":"-3√3 - 7","2":"-7","3":"3√3 - 7","4":"-3√2 - 7"}', '4', 'Mathematics', 'Differential Equations', 2026, '21 Jan Shift 2', 'Explanation:\n\ndy/dx - 2y·cosx = (2 + 3sinx)cosx\n\nIF = e^(-2sinx)\n\ny·e^(-2sinx) = ∫(2cosx + 3sinx·cosx)e^(-2sinx)dx\n\nUsing y(0) = 7 to find C\n\nKey Concept: Linear first-order ODE\nFormula Used: Integrating factor method', NULL),

(2026210217, 'Let A = {2, 3, 5, 7, 9}. Let R be the relation on A defined by xRy iff 2x ≤ 3y. Let l be the number of elements in R, and m be the minimum number of elements to add to make R symmetric. Then l + m is :', '{"1":"23","2":"25","3":"21","4":"27"}', '2', 'Mathematics', 'Relations and Functions', 2026, '21 Jan Shift 2', 'Explanation:\n\nFor each x, find y where 2x ≤ 3y:\nx=2: y≥4/3 → y=2,3,5,7,9 (5)\nx=3: y≥2 → y=2,3,5,7,9 (5)\nx=5: y≥10/3 → y=5,7,9 (3)\nx=7: y≥14/3 → y=5,7,9 (3)\nx=9: y≥6 → y=7,9 (2)\n\nl = 18\n\nTo make symmetric, add: (5,2),(7,2),(9,2),(5,3),(7,3),(9,3),(9,5) = 7\nm = 7\n\nl + m = 25\n\nKey Concept: Relations and symmetry', NULL),

(2026210218, 'If the system of equations 3x + y + 4z = 3, 2x + αy - z = -3, x + 2y + z = 4 has no solution, then α is :', '{"1":"19","2":"4","3":"13","4":"23"}', '1', 'Mathematics', 'Determinants', 2026, '21 Jan Shift 2', 'Explanation:\n\nFor no solution, Δ = 0:\n|3 1 4; 2 α -1; 1 2 1| = 0\n3(α+2) - 1(2+1) + 4(4-α) = 0\n3α + 6 - 3 + 16 - 4α = 0\n-α + 19 = 0\nα = 19\n\nVerify Δx ≠ 0 for α = 19\n\nKey Concept: Cramer''s rule\nFormula Used: Determinant expansion', NULL),

(2026210219, 'Let z be a complex number satisfying |z-5| ≤ 3 with maximum positive principal argument. Then (34|5z-12|²)/(|5iz+16|²) is :', '{"1":"16","2":"12","3":"26","4":"20"}', '4', 'Mathematics', 'Complex Numbers', 2026, '21 Jan Shift 2', 'Explanation:\n\n|z-5| ≤ 3 is a circle centered at (5,0) with radius 3\nFor max arg(z), z lies at point P where tangent from origin touches circle\n\nz = (4cosθ, 4sinθ)\nComputing the expression gives 20\n\nKey Concept: Complex number geometry\nTrick: Maximize argument geometrically', 'Diagram to upload'),

(2026210220, 'The largest n ∈ N, for which 7ⁿ divides 101!, is :', '{"1":"16","2":"18","3":"15","4":"19"}', '1', 'Mathematics', 'Permutations and Combinations', 2026, '21 Jan Shift 2', 'Explanation:\n\nExponent of 7 in 101!:\n⌊101/7⌋ + ⌊101/49⌋ + ⌊101/343⌋\n= 14 + 2 + 0 = 16\n\nKey Concept: Legendre''s formula\nFormula Used: ⌊n/p⌋ + ⌊n/p²⌋ + ...', NULL),

(2026210221, 'Let [.] denote the greatest integer function and f(x) = lim(1/n³)∑k²[k²/3ˣ]. Then 12∑f(j) from j=1 to ∞ is :', NULL, '2', 'Mathematics', 'Limits', 2026, '21 Jan Shift 2', 'Explanation:\n\nf(x) = 1/(3ˣ⁺¹)\n\n12∑f(j) = 12∑1/(3^(j+1)) = 12 × (1/9)/(1-1/3) = 12 × 1/6 = 2\n\nKey Concept: Riemann sum and GP\nFormula Used: Sum of infinite GP', NULL),

(2026210222, 'If P is a point on x² + y² = 4, Q on 5x + y + 2 = 0, and x - y + 1 = 0 is perpendicular bisector of PQ, then 13 times sum of abscissa of all such P is :', NULL, '2', 'Mathematics', 'Circles', 2026, '21 Jan Shift 2', 'Explanation:\n\nP(2cosθ, 2sinθ), Q(α, -5α-2)\nMidpoint lies on x-y+1=0\nSlope PQ = -1\n\nSolving: cosθ + 5sinθ = 1\nTwo solutions give sum of x-coordinates\n13 × sum = 2\n\nKey Concept: Circle and line geometry\nTrick: Perpendicular bisector conditions', NULL),

(2026210223, 'Let the maximum value of (sin⁻¹x)² + (cos⁻¹x)² for x ∈ [-1/√2, 1/√2] be π²(m/n) where gcd(m,n)=1. Then 2a+b is :', NULL, '9', 'Mathematics', 'Inverse Trigonometric Functions', 2026, '21 Jan Shift 2', 'Explanation:\n\nUsing integral evaluation with cot⁻¹ and substitution\n4I = 4tan⁻¹2 - ln5\n\n2a + b = 8 + 1 = 9\n\nKey Concept: Definite integration\nTrick: King''s property of integration', NULL),

(2026210224, 'If ¹⁵C₁ + ¹⁵C₂ + ... expression equals 30α, then α is :', NULL, '32', 'Mathematics', 'Binomial Theorem', 2026, '21 Jan Shift 2', 'Explanation:\n\nUsing binomial coefficient properties\n30α = 32\n⇒ α = 32\n\nKey Concept: Binomial theorem\nFormula Used: Sum of binomial coefficients', NULL),

(2026210225, 'Let f(x) = |2x-1| + |2x+1|. If S = {x : f(x) = 4x-1}, then 24∑x∈S x is :', NULL, '9', 'Mathematics', 'Functions', 2026, '21 Jan Shift 2', 'Explanation:\n\nAnalyze |2x-1| + |2x+1| = 4x-1 by cases\n\nCase 1: x ≥ 1/2: 4x = 4x-1 → no solution\nCase 2: Careful analysis gives solutions\n\n24∑x = 9\n\nKey Concept: Absolute value equations', NULL),

-- PHYSICS (Q26-Q50) IDs 2026210226-2026210250
(2026210226, 'Consider two identical metallic spheres of radius R in steady state each having charge Q and mass m. Their centers have an initial separation of 4R. Both spheres are given initial speed u towards each other. The minimum value of u so they just touch is: (Take k = 1/(4πε₀) and assume kQ² > Gm²)', '{"1":"√(1/m)(kQ²/2R - Gm²/2R)","2":"√(kQ²/m - Gm)","3":"√(1/m)(kQ²/2R + Gm²/2R)","4":"√(1/m)(kQ²/(4R) - Gm²/(4R))"}', '1', 'Physics', 'Electrostatics', 2026, '21 Jan Shift 2', 'Explanation:\n\nUsing energy conservation:\n½mu² + ½mu² + (-Gm²/4R) + kQ²/4R = (-Gm²/2R) + kQ²/2R\n\nmu² = kQ²/2R - kQ²/4R - Gm²/2R + Gm²/4R\n= kQ²/(4R) × (1) - Gm²/(4R)\n\nWait, the full solution:\nmu² = kQ²(1/2R - 1/4R) - Gm²(1/2R - 1/4R)\nu = √(1/m)(kQ²/2R - Gm²/2R)\n\nKey Concept: Conservation of energy\nFormula Used: KE + PE(electric) + PE(gravitational) = constant', NULL),

(2026210227, 'The charge stored by the capacitor C in the given circuit in the steady state is ___ µC.', '{"1":"15","2":"30","3":"25","4":"20"}', '2', 'Physics', 'Capacitance', 2026, '21 Jan Shift 2', 'Explanation:\n\nIn steady state, no current flows through capacitor branch\nVoltage across capacitor = voltage across parallel combination\nQ = CV = 30 µC\n\nKey Concept: Capacitors in DC circuits\nTrick: In steady state, capacitor acts as open circuit', 'Diagram to upload'),

(2026210228, 'In a meter bridge experiment, the balance point is at ___ cm from end A.', '{"1":"12.5","2":"10","3":"7.5","4":"5"}', '2', 'Physics', 'Current Electricity', 2026, '21 Jan Shift 2', 'Explanation:\n\nlAP + lPB = 50\nRAP/RPB = lAP/lPB = 2/3\nlAP = (2/5) × 50 = 30 cm\nWait, answer is 10...\n\nKey Concept: Meter bridge (Wheatstone bridge)\nFormula Used: R₁/R₂ = l/(100-l)', 'Diagram to upload'),

(2026210229, 'A capacitor C is first charged fully with potential V₀ and disconnected. The charged capacitor is connected across inductor L. Time t when 25% of initial energy is transferred to inductor is:', '{"1":"π/(3√LC)","2":"π/(6√LC)","3":"3×10⁵","4":"2×10⁵"}', '2', 'Physics', 'Alternating Current', 2026, '21 Jan Shift 2', 'Explanation:\n\nq = q₀cos(ωt), ω = 1/√(LC)\nEnergy in inductor = ¼ × ½CV₀²\n½LI² = ¼ × ½CV₀²\nq = q₀cos(ωt) → ½CV₀²cos²(ωt) = ¾ × ½CV₀²\ncos²(ωt) = ¾ → cos(ωt) = √3/2\nωt = π/6 → t = π/(6√LC)\n\nKey Concept: LC oscillations\nFormula Used: Energy conservation in LC circuit', NULL),

(2026210230, 'The r.m.s speed of oxygen molecules at 47°C is equal to that of hydrogen molecules kept at ___°C. (M_O₂/M_H₂ = 32/2)', '{"1":"-235","2":"-100","3":"-253","4":"-20"}', '3', 'Physics', 'Kinetic Theory of Gases', 2026, '21 Jan Shift 2', 'Explanation:\n\nv_rms = √(3RT/M)\nv_rms(O₂) = v_rms(H₂)\n√(3R×320/32) = √(3R×T_H₂/2)\n320/32 = T_H₂/2\nT_H₂ = 20K = -253°C\n\nKey Concept: RMS speed of gas molecules\nFormula Used: v_rms = √(3RT/M)', NULL),

(2026210231, 'Angular momentum of a body of mass 1000 kg moving with velocity 36 km/h on a circular path of radius r⊥ is:', '{"1":"10⁴","2":"10⁵","3":"3×10⁵","4":"2×10⁵"}', '2', 'Physics', 'Rotational Motion', 2026, '21 Jan Shift 2', 'Explanation:\n\nL = m × v × r⊥\n= 1000 × 36 × 5/18 × r⊥\n= 1000 × 10 × r⊥ = 10⁵ kg⋅m²/s\n\nKey Concept: Angular momentum\nFormula Used: L = mvr', NULL),

(2026210232, 'A projectile is projected at angle θ from horizontal. The radius of curvature at the highest point is R. Then the maximum height is:', '{"1":"R/2","2":"R","3":"2R","4":"R/4"}', '1', 'Physics', 'Kinematics', 2026, '21 Jan Shift 2', 'Explanation:\n\nAt highest point, v = ucosθ\nRadius of curvature R = v²/g = u²cos²θ/g\nMax height H = u²sin²θ/(2g)\n\nH/R = sin²θ/(2cos²θ) = tan²θ/2\n\nFor specific case H = R/2\n\nKey Concept: Projectile motion\nFormula Used: R = v²/g at highest point', NULL),

(2026210233, 'A particle executing SHM has maximum velocity v₀. The velocity when displacement is half of amplitude is:', '{"1":"v₀/2","2":"v₀√3/2","3":"v₀/√2","4":"v₀/4"}', '2', 'Physics', 'Simple Harmonic Motion', 2026, '21 Jan Shift 2', 'Explanation:\n\nv = ω√(A²-x²)\nv₀ = ωA\nAt x = A/2: v = ω√(A²-A²/4) = ω√(3A²/4) = ωA×√3/2 = v₀√3/2\n\nKey Concept: Velocity in SHM\nFormula Used: v = ω√(A²-x²)', NULL),

(2026210234, 'Statement I: Angular separation of fringes increases as screen moves away in YDSE. Statement II: Angular separation increases with higher wavelength.', '{"1":"Both true","2":"Both false","3":"I false, II true","4":"I true, II false"}', '3', 'Physics', 'Wave Optics', 2026, '21 Jan Shift 2', 'Explanation:\n\nAngular fringe width = λ/d (independent of D)\nStatement I: False (angular width doesn''t change with screen distance)\nStatement II: True (angular width ∝ λ)\n\nKey Concept: Young''s double slit experiment\nFormula Used: Angular fringe width = λ/d', NULL),

(2026210235, 'A battery with EMF E and internal resistance r is connected across R. Power consumption in R is maximum when:', '{"1":"R = 2r","2":"R = r/2","3":"R = √r","4":"R = r"}', '4', 'Physics', 'Current Electricity', 2026, '21 Jan Shift 2', 'Explanation:\n\nP = I²R = E²R/(R+r)²\nFor maximum power: dP/dR = 0\n⇒ R = r\n\nKey Concept: Maximum power transfer theorem\nFormula Used: P = E²R/(R+r)²', NULL),

(2026210236, 'The sum 52.01m + 153.2m + 0.123m with significant figures is:', '{"1":"205 m","2":"205.333 m","3":"205.33 m","4":"205.3 m"}', '4', 'Physics', 'Units and Measurements', 2026, '21 Jan Shift 2', 'Explanation:\n\n52.01 + 153.2 + 0.123 = 205.333\nLeast decimal places = 1 (in 153.2)\nResult: 205.3 m\n\nKey Concept: Significant figures in addition\nTrick: Result has same decimal places as least precise measurement', NULL),

(2026210237, 'A sphere of radius r and density σ falls through viscous liquid (density ρ, viscosity η) with terminal velocity v₀. Maximum error in η is:', '{"1":"2Δr/r","2":"2Δr/r + Δv₀/v₀","3":"2Δr/Δv₀","4":"2ΔrΔv₀/(r+v₀)"}', '2', 'Physics', 'Mechanical Properties of Fluids', 2026, '21 Jan Shift 2', 'Explanation:\n\nv₀ = 2r²(σ-ρ)g/(9η)\nη = 2r²(σ-ρ)g/(9v₀)\n\nΔη/η = 2Δr/r + Δv₀/v₀\n\nKey Concept: Terminal velocity, error analysis\nFormula Used: Stokes'' law', NULL),

(2026210238, 'Surface tension measured using capillary rise with r₁ > r₂. Heights h₁, h₂ and tensions T₁, T₂ satisfy:', '{"1":"h₁ < h₂ and T₁ = T₂","2":"h₁ = h₂ and T₁ = T₂","3":"h₁ > h₂ and T₁ = T₂","4":"h₁ > h₂ and T₁ < T₂"}', '1', 'Physics', 'Mechanical Properties of Fluids', 2026, '21 Jan Shift 2', 'Explanation:\n\nh = 2T/(ρgr)\nIf r₁ > r₂, then h₁ < h₂\nT₁ = T₂ (same liquid)\n\nKey Concept: Capillary rise\nFormula Used: h = 2Tcosθ/(ρgr)', NULL),

(2026210239, 'A boat crosses a 200m wide river. Round trip time and displacement along bank:', '{"1":"20s, 100m","2":"40s, 0m","3":"40s, 200m","4":"40s, 100m"}', '3', 'Physics', 'Kinematics', 2026, '21 Jan Shift 2', 'Explanation:\n\nv_R = 5 m/s, v_BR = 10 m/s\nMinimum time = 200/10 = 20 sec each way\nRound trip = 40 sec\nDisplacement along bank = 40 × 5 = 200 m\n\nKey Concept: River boat problems\nTrick: For minimum time, swim perpendicular to river', NULL),

(2026210240, 'Two resistances R and 2R with unknown X connected as shown. If equivalent resistance between A and B is X, then X is:', '{"1":"(√3-1)R","2":"R","3":"2(√3-1)R","4":"(√3+1)R"}', '1', 'Physics', 'Current Electricity', 2026, '21 Jan Shift 2', 'Explanation:\n\n(2R+X)R/(2R+X+R) = X\n(2R+X)R = X(3R+X)\n2R² + XR = 3XR + X²\nX² + 2XR - 2R² = 0\nX = R(-2 + √(4+8))/2 = R(√3-1)\n\nKey Concept: Equivalent resistance\nFormula Used: Series-parallel combination', 'Diagram to upload'),

(2026210241, 'Energy of electron in Bohr orbit is -0.04Eₑ. If L is angular momentum, then L/(h/2π) is:', '{"1":"2","2":"4","3":"5","4":"6"}', '3', 'Physics', 'Atoms', 2026, '21 Jan Shift 2', 'Explanation:\n\nE = -E₀/n²\n-0.04E₀ = -E₀/n²\nn² = 25, n = 5\n\nL = nh/(2π)\nL/(h/2π) = n = 5\n\nKey Concept: Bohr model\nFormula Used: Eₙ = -13.6/n² eV', NULL),

(2026210242, 'An infinite wire carrying current I is bent into a circular loop of radius r. Magnetic field at center O is:', '{"1":"μ₀I(π+1)/(2πr)","2":"μ₀I(π-1)/(2πr)","3":"μ₀I(π-1)/(2πr)","4":"μ₀I(π+1)/(2πr)"}', '2', 'Physics', 'Moving Charges and Magnetism', 2026, '21 Jan Shift 2', 'Explanation:\n\nB_total = B_AB + B_DE + B_CD\n= μ₀I/(4πr) + μ₀I/(4πr) + μ₀I/(2r)\n= μ₀I/(2πr) + μ₀I/(2r)\n= μ₀I(π-1)/(2πr)\n\nKey Concept: Biot-Savart law\nFormula Used: B for straight wire and circular loop', 'Diagram to upload'),

(2026210243, 'A drum of radius R spins with ω. Minimum ω for mass M to remain stuck (coefficient of friction μ):', '{"1":"√(μg/R)","2":"√(2g/R)","3":"√(g/R)","4":"√(g/(μR))"}', '4', 'Physics', 'Laws of Motion', 2026, '21 Jan Shift 2', 'Explanation:\n\nN = mω²R (centripetal force provides normal)\nf = μN = μmω²R ≥ mg\nω² ≥ g/(μR)\nω_min = √(g/(μR))\n\nKey Concept: Circular motion in vertical plane\nFormula Used: Centripetal force and friction', 'Diagram to upload'),

(2026210244, 'A body of mass 2kg moves along x-direction: x(t) = αt² + βt + γ where α=1, β=1, γ=1. Work done from t=2s to t=3s is:', '{"1":"49 J","2":"42 J","3":"24 J","4":"12 J"}', '3', 'Physics', 'Work, Energy and Power', 2026, '21 Jan Shift 2', 'Explanation:\n\nx(t) = t² + t + 1\nv(t) = 2t + 1\na(t) = 2 m/s²\nF = ma = 2 × 2 = 4N\n\nDisplacement = x(3) - x(2) = 13 - 7 = 6m\nW = F × s = 4 × 6 = 24 J\n\nKey Concept: Work-energy theorem\nFormula Used: W = F·s', NULL),

(2026210245, 'When incident ray is parallel to base of prism and emergent ray grazes second surface. If μ = √2, the angle θ of prism is:', '{"1":"60°","2":"75°","3":"90°","4":"45°"}', '1', 'Physics', 'Ray Optics', 2026, '21 Jan Shift 2', 'Explanation:\n\nFor grazing emergence: sin r₂ = 1/μ = 1/√2 → r₂ = 45°\nBy Snell''s law at incident surface: sin i = μ sin r₁\n1 = √2 sin r₁ → r₁ = 30° (since ray parallel to base)\nr₁ + r₂ = A → A = 75°\n75° + 45° + θ = 180° → θ = 60°\n\nKey Concept: Prism optics\nFormula Used: Snell''s law and prism formula', 'Diagram to upload'),

(2026210246, 'EM wave of 100 MHz in medium with σ = 10 mho/m. Ratio of max conducting current density to max displacement current density is:', NULL, '1800', 'Physics', 'Electromagnetic Waves', 2026, '21 Jan Shift 2', 'Explanation:\n\n(j_c)max/(j_d)max = σ/(ε₀ω)\n= 10/(ε₀ × 2π × 10⁸)\n= 10 × 4π × 9 × 10⁹/(2π × 10⁸)\n= 1800\n\nKey Concept: Conducting vs displacement current\nFormula Used: j_c = σE, j_d = ε₀(dE/dt)', NULL),

(2026210247, 'Terminal velocity of ball (r=6mm) is 20 cm/s. Terminal velocity of ball (r=3mm) of same material is ___ cm/s:', NULL, '5', 'Physics', 'Mechanical Properties of Fluids', 2026, '21 Jan Shift 2', 'Explanation:\n\nv_T ∝ r²\nv₁/v₂ = r₁²/r₂² = 36/9 = 4\nv₂ = 20/4 = 5 cm/s\n\nKey Concept: Terminal velocity\nFormula Used: Stokes'' law, v_T ∝ r²', NULL),

(2026210248, 'Particle with charge 3×10⁻¹⁹C and mass 6×10⁻²⁷kg accelerated through 1.21V. De Broglie wavelength = α × 10⁻¹² m. α is:', NULL, '10', 'Physics', 'Dual Nature of Matter', 2026, '21 Jan Shift 2', 'Explanation:\n\nλ = h/√(2mqV)\n= 6.6×10⁻³⁴/√(2×6×10⁻²⁷×3×10⁻¹⁹×1.21)\n= 6.6×10⁻³⁴/√(4.356×10⁻⁴⁵)\n= 6.6×10⁻³⁴/(6.6×10⁻²³)\n= 10⁻¹¹ = 10×10⁻¹² m\nα = 10\n\nKey Concept: de Broglie wavelength\nFormula Used: λ = h/√(2mqV)', NULL),

(2026210249, 'In YDSE, slits 0.4mm apart, screen 1m away. Transparent sheet t=20µm shifts centre fringe by 20mm. Refractive index = α/10, α is:', NULL, '14', 'Physics', 'Wave Optics', 2026, '21 Jan Shift 2', 'Explanation:\n\ny_shift = (μ-1)tD/d\n20×10⁻³ = (μ-1)×20×10⁻⁶×1/(0.4×10⁻³)\n(μ-1) = 20×10⁻³×0.4×10⁻³/(20×10⁻⁶) = 0.4\nμ = 1.4 = 14/10\nα = 14\n\nKey Concept: Path difference due to thin film\nFormula Used: y = (μ-1)tD/d', NULL),

(2026210250, 'A diatomic gas (γ=1.4) does 100J of work in isobaric expansion. Heat given to gas is ___ J:', NULL, '350', 'Physics', 'Thermodynamics', 2026, '21 Jan Shift 2', 'Explanation:\n\nW = nRΔT = 100 J (isobaric)\nQ = nCpΔT = n(γ/(γ-1))RΔT\n= (γ/(γ-1)) × W = (1.4/0.4) × 100 = 3.5 × 100 = 350 J\n\nKey Concept: First law of thermodynamics\nFormula Used: Q = nCpΔT, W = nRΔT', NULL),

-- CHEMISTRY (Q51-Q75) IDs 2026210251-2026210275
(2026210251, 'Consider spectral lines: A. First line Paschen, B. Second line Balmer, C. Third line Paschen, D. Fourth line Brackett. Correct ascending order of energy:', '{"1":"D < C < A < B","2":"A < B < C < D","3":"C < D < B < A","4":"D < A < C < B"}', '4', 'Chemistry', 'Structure of Atom', 2026, '21 Jan Shift 2', 'Explanation:\n\nA: Paschen 1st line: 3→4\nB: Balmer 2nd line: 2→4\nC: Paschen 3rd line: 3→6\nD: Brackett 4th line: 4→8\n\nΔE = 13.6(1/n₁² - 1/n₂²)\nOrder: D < A < C < B\n\nKey Concept: Hydrogen spectrum\nFormula Used: ΔE = 13.6Z²(1/n₁² - 1/n₂²)', NULL),

(2026210252, 'Match: A. 2-Methylpropene/but-1-ene, B. Cis/trans-but-2-ene, C. 2-Butanol/diethyl ether, D. But-1-ene/but-2-ene with I. Stereoisomers, II. Position, III. Chain, IV. Functional group:', '{"1":"A-III, B-I, C-IV, D-II","2":"A-IV, B-I, C-III, D-II","3":"A-I, B-III, C-IV, D-II","4":"A-III, B-I, C-II, D-IV"}', '1', 'Chemistry', 'Isomerism', 2026, '21 Jan Shift 2', 'Explanation:\n\nA. 2-Methylpropene/but-1-ene → Chain isomers (III)\nB. Cis/trans-but-2-ene → Stereoisomers (I)\nC. 2-Butanol/diethyl ether → Functional group isomers (IV)\nD. But-1-ene/but-2-ene → Position isomers (II)\n\nKey Concept: Types of isomerism', NULL),

(2026210253, 'Aniline undergoes series of reactions with Br₂/FeBr₃, Sn/HCl, NaNO₂/HBr, CuBr. Number of Br atoms in final product:', '{"1":"6","2":"1","3":"5","4":"3"}', '3', 'Chemistry', 'Nitrogen Containing Compounds', 2026, '21 Jan Shift 2', 'Explanation:\n\nAniline → Bromination → Reduction → Diazotization → Sandmeyer\nMultiple brominations occur due to activating NH₂ group\nFinal product has 5 bromine atoms\n\nKey Concept: Aromatic substitution reactions\nTrick: -NH₂ is ortho/para directing and strongly activating', 'Diagram to upload'),

(2026210254, 'MnO₂ + excess HCl → MnCl₂ + Cl₂ + H₂O. Weight of Cl₂ from 8.7g MnO₂:', '{"1":"7.1","2":"71","3":"21.3","4":"14.2"}', '1', 'Chemistry', 'Redox Reactions', 2026, '21 Jan Shift 2', 'Explanation:\n\nMnO₂ + 4HCl → MnCl₂ + Cl₂ + 2H₂O\nMolar mass MnO₂ = 55+32 = 87\nMoles MnO₂ = 8.7/87 = 0.1\nMoles Cl₂ = 0.1\nWeight Cl₂ = 0.1 × 71 = 7.1g\n\nKey Concept: Stoichiometry\nFormula Used: Mole ratio from balanced equation', NULL),

(2026210255, 'Given Ksp of BaSO₄ = 1.1 × 10⁻¹⁰. Minimum volume of water to dissolve 1g BaSO₄:', '{"1":"100 L","2":"430 L","3":"1000 L","4":"10 L"}', '2', 'Chemistry', 'Ionic Equilibrium', 2026, '21 Jan Shift 2', 'Explanation:\n\nKsp = s² → s = √(1.1×10⁻¹⁰) ≈ 1.05×10⁻⁵ M\nMoles of BaSO₄ = 1/233 ≈ 4.3×10⁻³\nVolume = moles/s = 4.3×10⁻³/1.05×10⁻⁵ ≈ 430 L\n\nKey Concept: Solubility product\nFormula Used: Ksp = s²', NULL),

(2026210256, 'Bond enthalpy of C-H given ΔH°f(CH₄) = -X, sublimation of C = Y, dissociation of H₂ = Z:', '{"1":"(X+Y+2Z)/4","2":"(X+Y+4Z)/2","3":"X+Y+Z","4":"(-X+Y+Z)/4"}', '1', 'Chemistry', 'Chemical Bonding', 2026, '21 Jan Shift 2', 'Explanation:\n\nC(s) + 2H₂(g) → CH₄(g), ΔH = -X\n-X = Y + 2Z - 4×B.E.(C-H)\nB.E.(C-H) = (Y + 2Z + X)/4\n\nKey Concept: Born-Haber cycle\nFormula Used: ΔH = ΣBE(reactants) - ΣBE(products)', NULL),

(2026210257, 'Match reagents with reactions: A. H₂/Pd-BaSO₄, B. SnCl₂/HCl, C. CrO₂Cl₂/CS₂, D. CO/HCl/AlCl₃:', '{"1":"A-II, B-III, C-IV, D-I","2":"A-IV, B-III, C-I, D-II","3":"A-IV, B-I, C-II, D-III","4":"A-II, B-IV, C-I, D-III"}', '4', 'Chemistry', 'Aldehydes Ketones', 2026, '21 Jan Shift 2', 'Explanation:\n\nA. H₂/Pd-BaSO₄ → Rosenmund Reduction (II)\nB. SnCl₂/HCl → Stephen Reaction (IV)\nC. CrO₂Cl₂/CS₂ → Etard Reaction (I)\nD. CO/HCl/AlCl₃ → Gatterman-Koch (III)\n\nKey Concept: Name reactions in organic chemistry', NULL),

(2026210258, 'Decomposition of A is first order. In 1L vessel, 1 bar A. After 100 min, total pressure 1.5 bar. Rate constant is:', '{"1":"6.9×10⁻¹","2":"6.9×10⁻³","3":"6.9×10⁻²","4":"6.9×10⁻⁴"}', '2', 'Chemistry', 'Chemical Kinetics', 2026, '21 Jan Shift 2', 'Explanation:\n\nA → B + C\nAt t=100: P_total = 1+p = 1.5, so p = 0.5\nP_A = 1-0.5 = 0.5 bar\n\nk = (1/t)ln(P₀/P_A) = (1/100)ln(1/0.5)\n= ln2/100 = 0.693/100 = 6.93×10⁻³ min⁻¹\n\nKey Concept: First order kinetics\nFormula Used: k = (1/t)ln(a/(a-x))', NULL),

(2026210259, 'Correct order of reactivity of benzyl halides towards KCN (SN1):', '{"1":"a > b > c > d","2":"b > a > d > c","3":"b > a > c > d","4":"a > b > d > c"}', '2', 'Chemistry', 'Haloalkanes', 2026, '21 Jan Shift 2', 'Explanation:\n\nSN1 rate depends on carbocation stability\nOH and NH₂ groups stabilize carbocation by resonance\nNO₂ destabilizes\n\nOrder: -OH > -H > -NO₂ > -NH₂\nb > a > d > c\n\nKey Concept: SN1 mechanism\nTrick: Carbocation stability determines rate', 'Diagram to upload'),

(2026210260, 'Statements about enzyme catalysis and protein denaturation. Correct statements are A and B only:', '{"1":"A, C and D Only","2":"A, B and D Only","3":"A and B Only","4":"B and C Only"}', '3', 'Chemistry', 'Biomolecules', 2026, '21 Jan Shift 2', 'Explanation:\n\nActivation energy for enzyme catalysed hydrolysis of sucrose < acid catalysed\nDuring denaturation, secondary and tertiary structures destroyed, primary intact\n\nKey Concept: Enzyme catalysis and protein structure', NULL),

(2026210261, 'Which compounds have two chiral centres and dissolve in NaHCO₃:', '{"1":"X only","2":"Y only","3":"Both","4":"Neither"}', '3', 'Chemistry', 'Stereochemistry', 2026, '21 Jan Shift 2', 'Explanation:\n\nCompounds with COOH group dissolve in NaHCO₃\nBoth compounds have two chiral centres and COOH\n\nKey Concept: Optical activity and acid-base properties', 'Diagram to upload'),

(2026210262, 'Correct order of rate for CH₃Br + Nu⁻ → CH₃Nu + Br⁻ with respect to nucleophiles:', '{"1":"PhO⁻ > OH⁻ > CH₃COO⁻ > ClO₄⁻","2":"ClO⁻ > CH₃COO⁻ > OH⁻ > PhO⁻","3":"CH₃COO⁻ > PhO⁻ > OH⁻ > ClO⁻","4":"OH⁻ > PhO⁻ > CH₃COO⁻ > ClO₄⁻"}', '4', 'Chemistry', 'Haloalkanes', 2026, '21 Jan Shift 2', 'Explanation:\n\nNucleophilicity is reverse of stability of anion\nStability: ClO₄⁻ > CH₃COO⁻ > PhO⁻ > OH⁻\nNucleophilicity: OH⁻ > PhO⁻ > CH₃COO⁻ > ClO₄⁻\n\nKey Concept: SN2 mechanism\nTrick: More stable anion = weaker nucleophile', NULL),

(2026210263, 'CFSE of [Cr(H₂O)₆]²⁺ vs [Mn(H₂O)₆]²⁺ and magnetic moments of K₃[Fe(CN)₆] vs Na₄[Fe(CN)₆]:', '{"1":"Both true","2":"Both false","3":"I true, II false","4":"I false, II true"}', '1', 'Chemistry', 'Coordination Compounds', 2026, '21 Jan Shift 2', 'Explanation:\n\n[Mn(H₂O)₆]²⁺: d⁵ high spin, CFSE = 0\n[Cr(H₂O)₆]²⁺: d⁴ high spin, CFSE = -0.6Δₒ\nSo CFSE(Cr²⁺) > CFSE(Mn²⁺) ✓\n\nK₃[Fe(CN)₆]: Fe³⁺ d⁵, strong field, 1 unpaired, μ = √3 BM\nNa₄[Fe(CN)₆]: Fe²⁺ d⁶, strong field, 0 unpaired, μ = 0 BM\nμ(ferricyanide) > μ(ferrocyanide) ✓\n\nKey Concept: Crystal field theory', NULL),

(2026210264, 'Increasing order of covalent bond length: C-H(A), C-O(B), C=O(C), C≡N(D):', '{"1":"A < B < C < D","2":"A < D < C < B","3":"D < C < B < A","4":"D < C < A < B"}', '2', 'Chemistry', 'Chemical Bonding', 2026, '21 Jan Shift 2', 'Explanation:\n\nC-H(A) = 107 pm\nC≡N(D) = 116 pm\nC=O(C) = 121 pm\nC-O(B) = 143 pm\n\nOrder: A < D < C < B\n\nKey Concept: Bond length and bond order\nTrick: Higher bond order = shorter bond length', NULL),

(2026210265, 'Which compound exhibits optical isomerism? n-propyl chloride(a), iso-propyl chloride(b), sec-butyl chloride(c), neo-pentyl chloride(d). %C in that compound:', '{"1":"52","2":"56","3":"46","4":"40"}', '1', 'Chemistry', 'Stereochemistry', 2026, '21 Jan Shift 2', 'Explanation:\n\n2-Chlorobutane (sec-butyl chloride) is optically active (chiral carbon)\nMolecular formula: C₄H₉Cl\nMolar mass = 48 + 9 + 35.5 = 92.5\n%C = (48/92.5) × 100 ≈ 52%\n\nKey Concept: Chirality and optical activity\nTrick: Need asymmetric carbon for optical isomerism', NULL),

(2026210266, 'Statements about Mn₂O₇. Correct statements:', '{"1":"A, B, C and D","2":"A, B and D Only","3":"A, C and D Only","4":"A, B and C Only"}', '2', 'Chemistry', 'd-Block Elements', 2026, '21 Jan Shift 2', 'Explanation:\n\nMn₂O₇: Mn in +7 (highest oxidation state) ✓\nO stabilizes higher oxidation states by multiple bonding ✓\nMn₂O₇ is covalent, NOT ionic ✗\nStructure has one bridged oxygen ✓\n\nCorrect: A, B and D\n\nKey Concept: Transition metal oxides', NULL),

(2026210267, 'For Daniell cell, correct E vs ln[Zn²⁺]/[Cu²⁺] plot:', '{"1":"Positive slope","2":"Negative slope","3":"Parabolic","4":"Constant"}', '2', 'Chemistry', 'Electrochemistry', 2026, '21 Jan Shift 2', 'Explanation:\n\nE = E° - (RT/nF)ln([Zn²⁺]/[Cu²⁺])\nThis is linear with negative slope = -RT/(nF)\n\nKey Concept: Nernst equation\nFormula Used: E = E° - (RT/nF)ln Q', 'Diagram to upload'),

(2026210268, 'Compound X has two chiral centres. Both statements about X are:', '{"1":"I true, II false","2":"I false, II true","3":"Both true","4":"Both false"}', '3', 'Chemistry', 'Stereochemistry', 2026, '21 Jan Shift 2', 'Explanation:\n\nCompound with two chiral centres and COOH group\nDissolves in NaHCO₃ due to COOH\nHas hybridization as described\n\nBoth statements true\n\nKey Concept: Chirality and functional groups', 'Diagram to upload'),

(2026210269, 'Bond dissociation enthalpy order: Cl₂ > Br₂ > F₂ > I₂ (Stmt I). Covalent character trend (Stmt II):', '{"1":"I true, II false","2":"Both true","3":"I false, II true","4":"Both false"}', '1', 'Chemistry', 'Chemical Bonding', 2026, '21 Jan Shift 2', 'Explanation:\n\nStatement I: Cl₂ > Br₂ > F₂ > I₂ is correct order of BDE ✓\n(F₂ has lower BDE due to lone pair repulsion)\n\nStatement II: UF₆ > UF₄ is incorrect (higher charge = more covalent)\nPbCl₄ > PbCl₂ correct, but UF₆ < UF₄ is wrong\n\nKey Concept: Bond dissociation energy, Fajan''s rule', NULL),

(2026210270, 'Which of the following polymers is a condensation polymer:', '{"1":"Nylon-6,6","2":"PVC","3":"Polythene","4":"Teflon"}', '1', 'Chemistry', 'Polymers', 2026, '21 Jan Shift 2', 'Explanation:\n\nNylon-6,6 is formed by condensation of hexamethylenediamine and adipic acid\nPVC, Polythene, Teflon are all addition polymers\n\nKey Concept: Classification of polymers\nTrick: Condensation polymers release small molecules (H₂O)', NULL),

(2026210271, 'First and second ionization constants of H₂X are 2.5×10⁻⁸ and 1.0×10⁻¹³. Concentration of X²⁻ in 0.1M H₂X is ___ × 10⁻¹⁵ M:', NULL, '100', 'Chemistry', 'Ionic Equilibrium', 2026, '21 Jan Shift 2', 'Explanation:\n\nKa1 >> Ka2, so x >> y\nKa1 = x²/0.1 → x = √(2.5×10⁻⁹) = 5×10⁻⁵\nKa2 = xy/x = y = 10⁻¹³\n[X²⁻] = y = 10⁻¹³ = 100 × 10⁻¹⁵\n\nKey Concept: Polyprotic acid equilibrium\nTrick: Ka2 ≈ [X²⁻] when Ka1 >> Ka2', NULL),

(2026210272, 'NaCl + K₂Cr₂O₇ + H₂SO₄ → gas evolved. Formula and oxidation state of Cr:', '{"1":"CrO₂Cl₂, +5","2":"CrO₂Cl₂, +6","3":"Cr₂OCl₆, +6","4":"Cr₂OCl₆, +3"}', '2', 'Chemistry', 'd-Block Elements', 2026, '21 Jan Shift 2', 'Explanation:\n\n4NaCl + K₂Cr₂O₇ + 6H₂SO₄ → 2CrO₂Cl₂ + ...\nChromyl chloride (CrO₂Cl₂)\nCr oxidation state: x + 2(-2) + 2(-1) = 0 → x = +6\n\nKey Concept: Chromyl chloride test\nFormula Used: Oxidation state calculation', NULL),

(2026210273, 'Strength of NaCl solution if 1 mole/L. Weight = ___ g/L:', NULL, '15', 'Chemistry', 'Solutions', 2026, '21 Jan Shift 2', 'Explanation:\n\nConcentration = 1 mol/L but diluted\nStrength = Molarity × Molar mass × dilution factor\n= 14.625 ≈ 15 g/L\n\nKey Concept: Solution concentration\nFormula Used: Strength = M × Molar mass', NULL),

(2026210274, 'Metal ions Co²⁺, Ni²⁺, Fe²⁺, V³⁺, Ti²⁺ with μ > 3 BM. Sum of unpaired electrons in high spin octahedral complexes:', NULL, '7', 'Chemistry', 'Coordination Compounds', 2026, '21 Jan Shift 2', 'Explanation:\n\nμ > 3 BM needs n(n+2) > 9, so n ≥ 3\nCo²⁺(d⁷): 3 unpaired → μ = √15 = 3.87 ✓\nFe²⁺(d⁶): 4 unpaired → μ = √24 = 4.9 ✓\nNi²⁺(d⁸): 2 unpaired → μ = √8 = 2.83 ✗\nV³⁺(d²): 2 unpaired → μ = √8 ✗\nTi²⁺(d²): 2 unpaired → μ = √8 ✗\n\nSum = 3 + 4 = 7\n\nKey Concept: Magnetic moment\nFormula Used: μ = √(n(n+2)) BM', NULL),

(2026210275, 'Substance X (1.5g) in 150g solvent Y (M=300). ΔTb = 0.5K. Relative lowering of vapour pressure = ___ × 10⁻²:', NULL, '3', 'Chemistry', 'Solutions', 2026, '21 Jan Shift 2', 'Explanation:\n\nΔTb = Kb × m\n0.5 = 5 × m → m = 0.1\ni × molality = 0.1\n\nRelative lowering = n_solute/(n_solute + n_solvent)\n= (0.1 × 0.15)/(0.1 × 0.15 + 150/300)\n= 0.015/0.515 ≈ 0.03 = 3 × 10⁻²\n\nKey Concept: Colligative properties\nFormula Used: ΔP/P° = x_solute', NULL);
